342	// TestProviderConnectivityViaService runs a HealthCheck against the named
343	// harness and translates the result into a ProviderStatus. It is the
344	// production replacement for Runner.TestProviderConnectivity.
345	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
346		status := ProviderStatus{Reachable: false}
347		if ctx == nil {
348			ctx = context.Background()
349		}
350		if harnessName == "virtual" || harnessName == "agent" {
351			status.Reachable = true
352			status.CreditsOK = true
353			return status
354		}
355		svc, err := NewServiceFromWorkDir(workDir)
356		if err != nil {
357			status.Error = err.Error()
358			return status
359		}
360		if timeout > 0 {
361			var cancel context.CancelFunc
362			ctx, cancel = context.WithTimeout(ctx, timeout)
363			defer cancel()
364		}
365		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
366			errStr := strings.ToLower(err.Error())
367			status.Error = err.Error()
368			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
369				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
370				status.CreditsOK = false
371			}
372			return status
373		}
374		status.Reachable = true
375		status.CreditsOK = true
376		return status
377	}
