379	// ValidateForExecuteLoopViaService is the production replacement for
380	// Runner.ValidateForExecuteLoop. When harness is empty it is a no-op (routing
381	// will pick at claim time). When harness is specified it confirms the harness
382	// exists in the service registry and (when model is set) attempts a
383	// ResolveRoute pre-flight.
384	func ValidateForExecuteLoopViaService(ctx context.Context, workDir, harnessName, model, provider, modelRef string) error {
385		if harnessName == "" {
386			return nil
387		}
388		if ctx == nil {
389			ctx = context.Background()
390		}
391		svc, err := NewServiceFromWorkDir(workDir)
392		if err != nil {
393			return fmt.Errorf("agent: build service: %w", err)
394		}
395		infos, err := svc.ListHarnesses(ctx)
396		if err != nil {
397			return fmt.Errorf("agent: list harnesses: %w", err)
398		}
399		found := false
400		for _, info := range infos {
401			if info.Name == harnessName {
402				found = true
403				if !info.Available {
404					return fmt.Errorf("agent: harness %s not available", harnessName)
405				}
406				break
407			}
408		}
409		if !found {
410			return fmt.Errorf("agent: unknown harness: %s", harnessName)
411		}
412	
413		// Pre-flight orphan-model check via ResolveRoute. Only meaningful when a
414		// model is provided and provider/model-ref are not set.
415		if model != "" && provider == "" && modelRef == "" && harnessName == "agent" {
416			if _, err := svc.ResolveRoute(ctx, agentlib.RouteRequest{
417				Model:    model,
418				Harness:  harnessName,
419				ModelRef: modelRef,
420				Provider: provider,
421			}); err != nil {
422				return fmt.Errorf("agent: model %q is not routable: %w", model, err)
423			}
424		}
425		return nil
426	}
