68	func SessionIndexDir(logDir string) string {
69		return filepath.Join(logDir, SessionIndexDirName)
70	}
71	
72	func SessionIndexShardName(t time.Time) string {
73		if t.IsZero() {
74			t = time.Now().UTC()
75		}
76		return fmt.Sprintf("sessions-%04d-%02d.jsonl", t.UTC().Year(), t.UTC().Month())
77	}
78	
79	func SessionIndexShardPath(logDir string, t time.Time) string {
80		return filepath.Join(SessionIndexDir(logDir), SessionIndexShardName(t))
81	}
82	
83	func ProjectIDForPath(path string) string {
84		canonical, err := filepath.Abs(path)
85		if err == nil {
86			path = canonical
87		}
88		h := sha256.Sum256([]byte(path))
89		return fmt.Sprintf("proj-%x", h[:4])
90	}
