92	func AppendSessionIndex(logDir string, entry SessionIndexEntry, now time.Time) error {
93		if logDir == "" {
94			return nil
95		}
96		if now.IsZero() {
97			now = time.Now().UTC()
98		}
99		if entry.ID == "" {
100			entry.ID = genSessionID()
101		}
102		if entry.StartedAt.IsZero() {
103			entry.StartedAt = now.UTC()
104		}
105		if entry.EndedAt.IsZero() && entry.DurationMS > 0 {
106			entry.EndedAt = entry.StartedAt.Add(time.Duration(entry.DurationMS) * time.Millisecond).UTC()
107		}
108		if entry.Outcome == "" {
109			if entry.ExitCode == 0 && entry.Detail == "" {
110				entry.Outcome = "success"
111			} else {
112				entry.Outcome = "failure"
113			}
114		}
115		if entry.BillingMode == "" {
116			entry.BillingMode = billingModeFor(entry.Harness, entry.Surface, entry.BaseURL)
117		}
118		if !ValidateBillingMode(entry.BillingMode) {
119			return fmt.Errorf("invalid billingMode %q", entry.BillingMode)
120		}
121		if err := os.MkdirAll(SessionIndexDir(logDir), 0o755); err != nil {
122			return err
123		}
124		data, err := json.Marshal(entry)
125		if err != nil {
126			return err
127		}
128		path := SessionIndexShardPath(logDir, now.UTC())
129		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
130		if err != nil {
131			return err
132		}
133		defer f.Close()
134		_, err = fmt.Fprintf(f, "%s\n", data)
135		return err
136	}
