149	func SessionIndexEntryFromResult(projectRoot string, inputs SessionIndexInputs, result *Result, startedAt, endedAt time.Time) SessionIndexEntry {
150		if result == nil {
151			result = &Result{}
152		}
153		corr := inputs.Correlation
154		id := ""
155		beadID := ""
156		workerID := ""
157		bundlePath := ""
158		baseRev := ""
159		nativeLogRef := ""
160		nativeSessionID := ""
161		traceID := ""
162		spanID := ""
163		if corr != nil {
164			id = corr["session_id"]
165			beadID = corr["bead_id"]
166			workerID = corr["worker_id"]
167			bundlePath = corr["bundle_path"]
168			baseRev = corr["base_rev"]
169			nativeLogRef = corr["native_log_ref"]
170			nativeSessionID = corr["native_session_id"]
171			traceID = corr["trace_id"]
172			spanID = corr["span_id"]
173		}
174		if id == "" {
175			id = genSessionID()
176		}
177		if bundlePath == "" && corr != nil && corr["attempt_id"] != "" {
178			bundlePath = filepath.Join(ExecuteBeadArtifactDir, corr["attempt_id"])
179		}
180		if nativeLogRef == "" && result.AgentSessionID != "" {
181			nativeLogRef = relativizePath(projectRoot, result.AgentSessionID)
182		}
183		if nativeSessionID == "" {
184			nativeSessionID = result.AgentSessionID
185		}
186		harness := result.Harness
187		if harness == "" {
188			harness = inputs.Harness
189		}
190		model := result.Model
191		if model == "" {
192			model = inputs.Model
193		}
194		outcome := "success"
195		if result.ExitCode != 0 || result.Error != "" {
196			outcome = "failure"
197		}
198		return SessionIndexEntry{
199			ID:              id,
200			ProjectID:       ProjectIDForPath(projectRoot),
201			BeadID:          beadID,
202			WorkerID:        workerID,
203			Harness:         harness,
204			Provider:        firstNonEmpty(result.Provider, inputs.Provider),
205			BaseURL:         result.ResolvedBaseURL,
206			BillingMode:     billingModeFor(harness, "", result.ResolvedBaseURL),
207			Model:           model,
208			StartedAt:       startedAt.UTC(),
209			EndedAt:         endedAt.UTC(),
210			DurationMS:      int(endedAt.Sub(startedAt).Milliseconds()),
211			CostUSD:         result.CostUSD,
212			CostPresent:     result.CostUSD != 0,
