299	func ReadSessionIndex(logDir string, q SessionIndexQuery) ([]SessionIndexEntry, error) {
300		files, err := SessionIndexShardFiles(logDir, q)
301		if err != nil {
302			return nil, err
303		}
304		var out []SessionIndexEntry
305		if q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
306			out, err = readRecentSessionIndexFiles(files, 1000)
307		} else {
308			out, err = readSessionIndexFiles(files, q)
309		}
310		if err != nil {
311			return nil, err
312		}
313		if len(out) == 0 && q.DefaultRecent && q.StartedAfter == nil && q.StartedBefore == nil {
314			files, err = SessionIndexShardFiles(logDir, SessionIndexQuery{})
315			if err != nil {
316				return nil, err
317			}
318			out, err = readSessionIndexFiles(files, q)
319			if err != nil {
320				return nil, err
321			}
322		}
323		sort.Slice(out, func(i, j int) bool {
324			return out[i].StartedAt.After(out[j].StartedAt)
325		})
326		return out, nil
327	}
