329	func readRecentSessionIndexFiles(files []string, perFile int) ([]SessionIndexEntry, error) {
330		var out []SessionIndexEntry
331		for _, file := range files {
332			data, err := os.ReadFile(file)
333			if os.IsNotExist(err) {
334				continue
335			}
336			if err != nil {
337				return nil, err
338			}
339			lines := bytes.Split(bytes.TrimSpace(data), []byte{'\n'})
340			start := 0
341			if perFile > 0 && len(lines) > perFile {
342				start = len(lines) - perFile
343			}
344			for _, line := range lines[start:] {
345				if len(bytes.TrimSpace(line)) == 0 {
346					continue
347				}
348				var entry SessionIndexEntry
349				if err := json.Unmarshal(line, &entry); err == nil {
350					out = append(out, entry)
351				}
352			}
353		}
354		return out, nil
355	}
