636	func bodiesFromResultJSON(data []byte) (string, string) {
637		var raw map[string]any
638		if err := json.Unmarshal(data, &raw); err != nil {
639			return "", ""
640		}
641		response := firstString(raw, "response", "output", "final_text", "finalText", "detail")
642		stderr := firstString(raw, "stderr", "error")
643		return response, stderr
644	}
