646	func bodiesFromNativeLog(path string) (string, string) {
647		f, err := os.Open(path)
648		if err != nil {
649			return "", ""
650		}
651		defer f.Close()
652		var response, stderr string
653		scanner := bufio.NewScanner(f)
654		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
655		for scanner.Scan() {
656			var raw map[string]any
657			if err := json.Unmarshal(scanner.Bytes(), &raw); err != nil {
658				continue
659			}
660			if s := firstNestedString(raw, []string{"data", "final_text"}, []string{"data", "finalText"}, []string{"final_text"}, []string{"finalText"}); s != "" {
661				response = s
662			}
663			if s := firstNestedString(raw, []string{"data", "error"}, []string{"error"}, []string{"stderr"}); s != "" {
664				stderr = s
665			}
666		}
667		return response, stderr
668	}
669	
670	func firstString(raw map[string]any, keys ...string) string {
671		for _, key := range keys {
672			if s, ok := raw[key].(string); ok && s != "" {
673				return s
674			}
675		}
676		return ""
677	}
678	
679	func firstNestedString(raw map[string]any, paths ...[]string) string {
680		for _, path := range paths {
681			cur := any(raw)
682			for _, key := range path {
683				m, ok := cur.(map[string]any)
684				if !ok {
685					cur = nil
686					break
687				}
688				cur = m[key]
689			}
690			if s, ok := cur.(string); ok && s != "" {
691				return s
692			}
693		}
694		return ""
695	}
