87	// executeOnService dispatches against a pre-built svc using the durable
88	// knobs from rcfg and per-invocation plumbing from runtime, then records
89	// one session-index row. It is the inlined replacement for the retired
90	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
91	func executeOnService(ctx context.Context, svc agentlib.DdxAgent, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
92		if svc == nil {
93			return nil, fmt.Errorf("agent: nil service")
94		}
95		if ctx == nil {
96			ctx = context.Background()
97		}
98	
99		promptText := runtime.Prompt
100		if runtime.PromptFile != "" {
101			data, err := readPromptFileBounded(runtime.PromptFile)
102			if err != nil {
103				return nil, fmt.Errorf("agent: read prompt file: %w", err)
104			}
105			promptText = string(data)
106		}
107		if promptText == "" {
108			return nil, fmt.Errorf("agent: prompt is required")
109		}
110	
111		wd := runtime.WorkDir
112		if wd == "" {
113			wd = workDir
114		}
115		if wd == "" {
116			wd, _ = os.Getwd()
117		}
118	
119		idle := rcfg.Timeout()
120		if idle <= 0 {
121			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
122		}
123		wall := rcfg.WallClock()
124		if wall <= 0 {
125			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
126		}
127	
128		sessionLogDir := runtime.SessionLogDirOverride
129		if sessionLogDir == "" {
130			sessionLogDir = rcfg.SessionLogDir()
131		}
132		if sessionLogDir == "" {
133			sessionLogDir = ResolveLogDir(workDir, "")
134		}
135	
136		pt := rcfg.Passthrough()
137	
138		harness := runtime.HarnessOverride
139		if harness == "" {
140			harness = pt.Harness
141		}
142	
143		model := runtime.ModelOverride
144		if model == "" {
145			model = pt.Model
146		}
147	
148		permissions := runtime.PermissionsOverride
149		if permissions == "" {
150			permissions = rcfg.Permissions()
151		}
152	
153		providerTimeout := ResolveProviderRequestTimeout(workDir, pt.Provider, model, rcfg.ProviderRequestTimeout())
154	
155		req := agentlib.ServiceExecuteRequest{
156			Prompt:          promptText,
157			Model:           model,
158			Provider:        pt.Provider,
159			Harness:         harness,
160			ModelRef:        rcfg.ModelRef(),
161			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
162			Permissions:     permissions,
163			WorkDir:         wd,
164			Timeout:         wall,
165			IdleTimeout:     idle,
166			ProviderTimeout: providerTimeout,
167			SessionLogDir:   sessionLogDir,
168			Metadata:        runtime.Correlation,
169			MinPower:        rcfg.MinPower(),
170			MaxPower:        rcfg.MaxPower(),
171		}
172	
173		cancelCtx, cancel := context.WithCancel(ctx)
174		defer cancel()
175	
176		start := time.Now().UTC()
177		events, err := svc.Execute(cancelCtx, req)
178		if err != nil {
179			return nil, fmt.Errorf("agent: execute: %w", err)
180		}
181	
182		final, toolCalls, routing, actualPower := drainServiceEvents(events)
183		finishedAt := time.Now().UTC()
184		elapsed := finishedAt.Sub(start)
185	
186		result := &Result{
187			Harness:    harness,
188			Model:      model,
189			DurationMS: int(elapsed.Milliseconds()),
190			ToolCalls:  toolCalls,
191		}
192		if routing != nil {
193			result.Provider = routing.Provider
194			if routing.Model != "" {
195				result.Model = routing.Model
196			}
197			if routing.Harness != "" {
198				result.Harness = routing.Harness
199			}
200		}
201		if actualPower > 0 {
202			result.ActualPower = actualPower
203		}
204		if final != nil {
205			// Normalized final text from the upstream harness (agent-32e8ff5e);
206			// reviewer verdict extraction now parses this instead of raw stream
207			// frames (ddx-7bc0c8d5).
208			result.Output = final.FinalText
209			if final.Usage != nil {
210				// v0.9.1: Usage fields became *int (nullable).
211				if final.Usage.InputTokens != nil {
212					result.InputTokens = *final.Usage.InputTokens
213				}
214				if final.Usage.OutputTokens != nil {
215					result.OutputTokens = *final.Usage.OutputTokens
216				}
217				if final.Usage.TotalTokens != nil {
218					result.Tokens = *final.Usage.TotalTokens
219				}
220			}
221			if final.CostUSD > 0 {
222				result.CostUSD = final.CostUSD
223			}
224			if final.RoutingActual != nil {
225				if result.Provider == "" {
226					result.Provider = final.RoutingActual.Provider
227				}
228				if final.RoutingActual.Model != "" {
229					result.Model = final.RoutingActual.Model
230				}
231			}
232			switch final.Status {
233			case "success", "":
234				// happy path
235			case "stalled":
236				result.ExitCode = 1
237				if final.Error != "" {
238					result.Error = "stalled: " + final.Error
239				} else {
240					result.Error = "stalled"
241				}
242			case "timed_out":
243				result.ExitCode = 1
244				result.Error = fmt.Sprintf("timeout after %v", wall.Round(time.Second))
245			case "cancelled":
246				result.ExitCode = 1
247				result.Error = "cancelled"
248			default:
249				result.ExitCode = 1
250				if final.Error != "" {
251					result.Error = final.Error
252				} else {
253					result.Error = final.Status
254				}
255			}
256			result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
257			if final.SessionLogPath != "" {
258				result.AgentSessionID = final.SessionLogPath
259			}
260		}
261		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
262			Harness:     harness,
263			Model:       model,
264			Provider:    pt.Provider,
265			Effort:      rcfg.Effort(),
266			Correlation: runtime.Correlation,
267		}, result, start, finishedAt)
268		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
269		return result, nil
270	}
