272	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
273	// querying the service's ListHarnesses and (best-effort) the harness registry.
274	// It is the production replacement for Runner.Capabilities.
275	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
276		if ctx == nil {
277			ctx = context.Background()
278		}
279		svc, err := NewServiceFromWorkDir(workDir)
280		if err != nil {
281			return nil, fmt.Errorf("agent: build service: %w", err)
282		}
283		infos, err := svc.ListHarnesses(ctx)
284		if err != nil {
285			return nil, fmt.Errorf("agent: list harnesses: %w", err)
286		}
287		var info *agentlib.HarnessInfo
288		for i := range infos {
289			if infos[i].Name == harnessName {
290				info = &infos[i]
291				break
292			}
293		}
294		if info == nil {
295			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
296		}
297	
298		// Pull binary and reasoning-level metadata from the local registry — the
299		// service does not expose these directly today.
300		registry := newHarnessRegistry()
301		harness, _ := registry.Get(harnessName)
302	
303		caps := &HarnessCapabilities{
304			Harness:             info.Name,
305			Available:           info.Available,
306			Binary:              harness.Binary,
307			Path:                info.Path,
308			Surface:             harness.Surface,
309			CostClass:           info.CostClass,
310			IsLocal:             info.IsLocal,
311			ExactPinSupport:     info.ExactPinSupport,
312			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
313			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
314		}
315		if len(info.SupportedReasoning) > 0 {
316			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
317		} else if len(harness.ReasoningLevels) > 0 {
318			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
319		}
320	
321		if harness.DefaultModel != "" {
322			caps.Model = harness.DefaultModel
323			caps.Models = []string{harness.DefaultModel}
324		}
325	
326		// Profile mappings come from the local model catalog because the service
327		// does not surface a per-tier resolution endpoint today.
328		if harness.Surface != "" {
329			cat := BuiltinCatalog
330			for _, profile := range []string{"cheap", "fast", "smart"} {
331				if m, ok := cat.Resolve(profile, harness.Surface); ok {
332					if caps.ProfileMappings == nil {
333						caps.ProfileMappings = make(map[string]string)
334					}
335					caps.ProfileMappings[profile] = m
336				}
337			}
338		}
339		return caps, nil
340	}
